// Extract the last user message and build conversation string
const body = $input.first().json.body;
const messages = body.messages || [];

// Get last user message
const lastMsg = messages.filter(m => m.role === 'user').slice(-1)[0];
const userInput = lastMsg ? lastMsg.content : '';

// Build chat history string for context (last 8 messages)
const history = messages.slice(-8).map(m => 
  `${m.role === 'user' ? 'User' : 'Assistant'}: ${m.content}`
).join('\n');

// Session ID: based on first message content for memory continuity
const firstMsg = messages[0]?.content || 'default';
const sessionId = 'session_' + firstMsg.slice(0, 20).replace(/[^a-z0-9]/gi, '_').toLowerCase();

return [{
  json: {
    userInput,
    chatHistory: history,
    sessionId,
    messageCount: messages.length
  }
}];
